  9	import { ChartLegendTooltipStyles } from '@patternfly/react-charts/dist/esm/components/ChartTheme/ChartStyles';
 10	import {
 11	  getLegendTooltipDataProps,
 12	  getLegendTooltipSize,
 13	  getLegendTooltipVisibleData,
 14	  getLegendTooltipVisibleText,
 15	} from '@patternfly/react-charts/dist/esm/components/ChartUtils/chart-tooltip';
 16	import ChartLegendTooltipContent from '@utils/components/Area/components/ChartLegendTooltipContent';
 17	import { DataPoint } from '@utils/components/Area/utils/types';
 18	import { evaluateProp } from '@utils/components/Area/utils/utils';
 19	
 20	const ChartLegendTooltip: FC<
 21	  Omit<ChartLegendTooltipProps, 'title'> & {
 22	    formatDate: (data: DataPoint<Date>[]) => string;
 23	    getLabel?: (prop: { datum: DataPoint<Date> }) => string;
 24	    mainDataName: string;
 25	    stack?: boolean;
 26	  }
 27	> = (props) => {
 28	  const {
 29	    activePoints,
 30	    center = { x: 0, y: 0 },
 31	    datum,
 32	    flyoutHeight,
 33	    flyoutWidth,
 34	    formatDate,
 35	    getLabel,
 36	    height,
 37	    isCursorTooltip = true,
 38	    mainDataName, // eslint-disable-next-line perfectionist/sort-objects
 39	    labelComponent = <ChartLegendTooltipContent mainDataName={mainDataName} />,
 40	    legendData,
 41	    stack,
 42	    text,
 43	    themeColor, // eslint-disable-next-line perfectionist/sort-objects
 44	    width, // eslint-disable-next-line perfectionist/sort-objects
 45	    // destructure last
 46	    theme = getTheme(themeColor), // eslint-disable-line perfectionist/sort-objects
 47	    ...rest
 48	  } = props;
 49	  const title = (d) => {
 50	    if (stack) {
 51	      return formatDate(d);
 52	    }
 53	    const mainDatum = mainDataName ? d.find((uDatum) => uDatum.childName === mainDataName) : d[0];
 54	    return mainDatum ? getLabel({ datum: mainDatum }) : `No ${mainDataName || 'data'} available`;
 55	  };
 56	  const pointerLength = theme?.tooltip ? evaluateProp(theme.tooltip.pointerLength, props) : 10;
 57	  const legendTooltipProps = {
 58	    legendData: getLegendTooltipVisibleData({ activePoints, legendData, text, theme }),
 59	    legendProps: getLegendTooltipDataProps(labelComponent.props.legendComponent),
 60	    text: getLegendTooltipVisibleText({ activePoints, legendData, text }),
 61	    theme,
 62	  };
 63	
 64	  // Returns flyout height based on legend size
 65	  const getFlyoutHeight = () => {
 66	    const sizeProps = stack
 67	      ? legendTooltipProps
 68	      : {
 69	          ...legendTooltipProps,
 70	          // For non-stack graphs, remove the text for "mainDataName"
 71	          text: legendTooltipProps.text.filter(
 72	            (t, i) => legendTooltipProps.legendData[i].name !== mainDataName,
 73	          ),
 74	        };
 75	    const _flyoutHeight =
 76	      getLegendTooltipSize(sizeProps).height + ChartLegendTooltipStyles.flyout.padding;
 77	    return title ? _flyoutHeight + 4 : _flyoutHeight - 10;
 78	  };
 79	
 80	  // Returns flyout width based on legend size
 81	  const getFlyoutWidth = () =>
 82	    getLegendTooltipSize(legendTooltipProps).width +
 83	    ChartLegendTooltipStyles.flyout.padding +
 84	    (stack ? 20 : 0);
 85	
 86	  // Returns the tooltip content component
 87	  const getTooltipContentComponent = () =>
 88	    cloneElement(labelComponent, {
 89	      center,
 90	      flyoutHeight: flyoutHeight || getFlyoutHeight(),
 91	      flyoutWidth: flyoutWidth || getFlyoutWidth(),
 92	      height,
 93	      legendData,
 94	      stack,
 95	      title,
 96	      width,
 97	      ...labelComponent.props,
 98	    });
 99	
100	  // Returns the tooltip component
101	  const getTooltipComponent = () => {
102	    const _flyoutWidth = getFlyoutWidth();
103	    const tooltipComponent = isCursorTooltip ? <ChartCursorTooltip /> : <ChartTooltip />;
104	    return cloneElement(tooltipComponent, {
105	      activePoints,
106	      center,
107	      datum,
108	      flyoutHeight: flyoutHeight || getFlyoutHeight(),
109	      flyoutWidth: flyoutWidth || getFlyoutWidth(),
110	      height,
111	      labelComponent: getTooltipContentComponent(),
112	      ...(flyoutWidth === undefined && {
113	        showPointer:
114	          width > _flyoutWidth + center.x + pointerLength ||
115	          center.x > _flyoutWidth + pointerLength,
116	      }),
117	      text,
118	      theme,
119	      width,
120	      ...rest,
121	    });
122	  };
123	
124	  return getTooltipComponent();
125	};
126	
127	export default ChartLegendTooltip;

